GRANT  EXECUTE ON FUNCTION public.get_student_billing_summary(UUID) TO authenticated;


-- ============================================================
-- SECTION 10: pg_cron JOB
-- Monthly auto-generation of fee dues.
-- Fires at 19:00 UTC = 00:30 IST on the 1st of every month.
-- Safe unschedule: uses DO block to check existence first.
-- CONFLICT REMOVED: first attempt used invalid
--   SELECT cron.unschedule() WHERE EXISTS — not valid SQL.
--   Final version uses DO $$ IF EXISTS THEN PERFORM $$ pattern.
-- ============================================================

DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM cron.job WHERE jobname = 'auto-generate-monthly-dues'
  ) THEN
    PERFORM cron.unschedule('auto-generate-monthly-dues');
  END IF;
END $$;

SELECT cron.schedule(
  'auto-generate-monthly-dues',
  '0 19 1 * *',    -- 19:00 UTC = 00:30 IST on 1st of every month
  $$
    SELECT public.auto_generate_monthly_dues(NULL);
  $$
);

